164	// scanRunStore reads FEAT-010 run JSON files from .ddx/exec/runs/.
165	func scanRunStore(projectRoot string) []*ddxgraphql.Run {
166		dir := filepath.Join(projectRoot, runStoreDir)
167		entries, err := os.ReadDir(dir)
168		if err != nil {
169			return nil
170		}
171		out := make([]*ddxgraphql.Run, 0, len(entries))
172		for _, entry := range entries {
173			if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".json") {
174				continue
175			}
176			data, err := os.ReadFile(filepath.Join(dir, entry.Name()))
177			if err != nil {
178				continue
179			}
180			var rec runRecord
181			if err := json.Unmarshal(data, &rec); err != nil || rec.ID == "" {
182				continue
183			}
184			out = append(out, runRecordToGQL(rec))
185		}
186		return out
187	}
