189	// synthesizeRunsFromBundles derives try-layer Run records from .ddx/executions/
190	// bundle directories. Each bundle = one execute-bead attempt (a "try" in the
191	// three-layer model). Run-layer records are synthesized separately from the
192	// AgentSession index, since multiple agent invocations may share a try.
193	func synthesizeRunsFromBundles(projectID, projectRoot string) []*ddxgraphql.Run {
194		dir := filepath.Join(projectRoot, agent.ExecuteBeadArtifactDir)
195		entries, err := os.ReadDir(dir)
196		if err != nil {
197			return nil
198		}
199		out := make([]*ddxgraphql.Run, 0, len(entries))
200		for _, entry := range entries {
201			if !entry.IsDir() {
202				continue
203			}
204			name := entry.Name()
205			if !looksLikeBundleID(name) {
206				continue
207			}
208			bundleDirAbs := filepath.Join(dir, name)
209			exec := loadExecutionBundle(projectID, projectRoot, bundleDirAbs, name)
210			if exec == nil {
211				continue
212			}
213			run := executionBundleToRun(name, exec)
214			out = append(out, run)
215		}
216		sort.Slice(out, func(i, j int) bool {
217			si, sj := "", ""
218			if out[i].StartedAt != nil {
219				si = *out[i].StartedAt
220			}
221			if out[j].StartedAt != nil {
222				sj = *out[j].StartedAt
223			}
224			return si > sj
225		})
226		return out
227	}
