410	// parentTryIDFromBundlePath returns the synthesized try-layer Run ID
411	// ("exec-<bundle-id>") for a bundle path under .ddx/executions/, or "" when
412	// the path does not look like a bundle.
413	func parentTryIDFromBundlePath(p string) string {
414		clean := filepath.ToSlash(p)
415		prefix := filepath.ToSlash(agent.ExecuteBeadArtifactDir) + "/"
416		idx := strings.Index(clean, prefix)
417		if idx < 0 {
418			return ""
419		}
420		rest := clean[idx+len(prefix):]
421		if i := strings.Index(rest, "/"); i >= 0 {
422			rest = rest[:i]
423		}
424		if !looksLikeBundleID(rest) {
425			return ""
426		}
427		return "exec-" + rest
428	}
