467	// loadRunsForProject loads runs for a single project, merging the file store
468	// with synthesized execution bundle records.
469	func (s *ServerState) loadRunsForProject(projectID, projectRoot string) []*ddxgraphql.Run {
470		// Primary: FEAT-010 run store
471		stored := scanRunStore(projectRoot)
472	
473		// Secondary: synthesize run-layer records from .ddx/executions/ bundles,
474		// but only include IDs that are not already in the stored set.
475		storedIDs := make(map[string]bool, len(stored))
476		for _, r := range stored {
477			storedIDs[r.ID] = true
478		}
479	
480		synthesized := synthesizeRunsFromBundles(projectID, projectRoot)
481		for _, r := range synthesized {
482			if !storedIDs[r.ID] {
483				stored = append(stored, r)
484				storedIDs[r.ID] = true
485			}
486		}
487	
488		sessions := synthesizeRunsFromSessions(projectID, projectRoot)
489		for _, r := range sessions {
490			if !storedIDs[r.ID] {
491				stored = append(stored, r)
492				storedIDs[r.ID] = true
493			}
494		}
495	
496		// Sort newest-first by startedAt.
497		sort.Slice(stored, func(i, j int) bool {
498			si, sj := "", ""
499			if stored[i].StartedAt != nil {
500				si = *stored[i].StartedAt
501			}
502			if stored[j].StartedAt != nil {
503				sj = *stored[j].StartedAt
504			}
505			return si > sj
506		})
507		return tagProjectID(stored, projectID)
508	}
509	
510	// GetRunGraphQL implements RunsStateProvider.
511	func (s *ServerState) GetRunGraphQL(id string) (*ddxgraphql.Run, bool) {
512		if id == "" {
513			return nil, false
514		}
515		// Search all projects.
516		for _, proj := range s.GetProjects(false) {
517			runs := s.loadRunsForProject(proj.ID, proj.Path)
518			for _, r := range runs {
519				if r.ID == id {
520					s.loadRunDetail(r)
521					return r, true
522				}
523			}
524		}
525		return nil, false
526	}
