142	// listRunBundleFiles walks the bundle root and returns one RunBundleFile per
143	// regular file. Symlinks pointing outside the root are skipped.
144	func listRunBundleFiles(bundleRoot string) []*ddxgraphql.RunBundleFile {
145		var out []*ddxgraphql.RunBundleFile
146		if bundleRoot == "" {
147			return out
148		}
149		_ = filepath.Walk(bundleRoot, func(p string, info os.FileInfo, err error) error {
150			if err != nil || info == nil {
151				return nil
152			}
153			if info.IsDir() {
154				return nil
155			}
156			// Skip anything that, after symlink resolution, escapes the root.
157			if eval, err := filepath.EvalSymlinks(p); err == nil {
158				rel, err := filepath.Rel(bundleRoot, filepath.Clean(eval))
159				if err != nil || rel == ".." || strings.HasPrefix(rel, ".."+string(filepath.Separator)) {
160					return nil
161				}
162			}
163			rel, err := filepath.Rel(bundleRoot, p)
164			if err != nil {
165				return nil
166			}
167			size := int(info.Size())
168			mt := mimeTypeForPath(rel)
169			out = append(out, &ddxgraphql.RunBundleFile{
170				Path:     filepath.ToSlash(rel),
171				Size:     size,
172				MimeType: mt,
173			})
174			return nil
175		})
176		sort.Slice(out, func(i, j int) bool { return out[i].Path < out[j].Path })
177		return out
178	}
